#include "sse_server.h"
#include <WiFi.h>
#include <ESPAsyncWebServer.h>
static AsyncWebServer*_srv=nullptr;
static AsyncEventSource*_events=nullptr;
void sse_setup(uint16_t port,const char*path){_srv=new AsyncWebServer(port);_events=new AsyncEventSource(path);_srv->addHandler(_events);_srv->begin();Serial.printf("[sse] OK port=%d path=%s\n",port,path);}
void sse_send(const char*ev,const char*d){if(_events)_events->send(d,ev,millis());}
